mapper.select:
select cps.id, cps.sku_code, cps.sku_name, cps.product_id, cps.create_time, cps.origin_price, cps.current_price, cps.sku_pics, cps.amount, cps.limit_amount, cps.state, cps.if_default, cps.update_time, cps.sort_order, cps.remarks, cmi.merchant_name, cp.product_name from cm_product_sku cps left join cm_product cp on cps.product_id = cp.id left join cm_merchant_info cmi on cp.merchant_id = cmi.id where cps.deleted = '0' and cmi.deleted = '0'
and cp.merchant_id = #{vo.merchantId}
and cps.sku_code = #{vo.skuCode}
and cps.sku_name like concat('%', #{vo.skuName}, '%')
and cp.product_name like concat('%', #{vo.productName}, '%')
and cps.state = #{vo.state}
and cps.current_price >= cast(#{vo.priceMin} as DECIMAL)
and cps.sku_name < cast(#{vo.priceMax} as DECIMAL)
order by cps.create_time desc
